# FastAPI middleware that injects deprecation headers
from fastapi import Request, Response
from fastapi.middleware.base import BaseHTTPMiddleware
from datetime import datetime

DEPRECATED_PATHS = {
    "/v1/completions": {
        "sunset_date": "2026-01-31",
        "successor": "/v2/messages",
        "docs": "https://docs.example.com/migration/v1-to-v2",
    },
}

class DeprecationHeaderMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        response: Response = await call_next(request)

        for path, info in DEPRECATED_PATHS.items():
            if request.url.path.startswith(path):
                response.headers["Deprecation"] = "true"
                response.headers["Sunset"] = info["sunset_date"]
                response.headers["Link"] = (
                    f'<{info["docs"]}>; rel="deprecation", '
                    f'<{info["successor"]}>; rel="successor-version"'
                )
                break

        return response

import anthropic
import warnings

# In your SDK wrapper: warn at the call site when a deprecated model is used
DEPRECATED_MODELS = {
    "claude-2.0": {
        "sunset": "2026-03-01",
        "replacement": "claude-3-5-haiku-20241022",
    },
}

class DeprecationAwareAnthropicClient:
    def __init__(self):
        self._client = anthropic.Anthropic()

    def create_message(self, model: str, **kwargs):
        if model in DEPRECATED_MODELS:
            info = DEPRECATED_MODELS[model]
            warnings.warn(
                f"Model '{model}' is deprecated and will be removed on "
                f"{info['sunset']}. Use '{info['replacement']}' instead.",
                DeprecationWarning,
                stacklevel=2,
            )
        return self._client.messages.create(model=model, **kwargs)

# Callers see a DeprecationWarning in their logs without changing behaviour
client = DeprecationAwareAnthropicClient()
response = client.create_message(
    model="claude-2.0",  # triggers warning
    max_tokens=100,
    messages=[{"role": "user", "content": "Hello"}],
)

// React component that shows a sunset banner based on feature flags
import React from "react";

interface SunsetBannerProps {
  featureId: string;
  sunsetDate: string;
  migrationUrl: string;
  daysRemaining: number;
}

export function SunsetBanner({
  featureId,
  sunsetDate,
  migrationUrl,
  daysRemaining,
}: SunsetBannerProps) {
  const severity = daysRemaining <= 30 ? "error" : daysRemaining <= 90 ? "warning" : "info";

  const colours = {
    error: "bg-red-50 border-red-400 text-red-800",
    warning: "bg-yellow-50 border-yellow-400 text-yellow-800",
    info: "bg-blue-50 border-blue-400 text-blue-800",
  };

  return (
    <div className={`border rounded p-4 mb-4 ${colours[severity]}`}>
      <strong>Feature retiring on {sunsetDate}</strong> ({daysRemaining} days remaining){" "}
      — This feature ({featureId}) will be permanently disabled.
      {" "}
      <a href={migrationUrl} className="underline font-semibold">
        Read the migration guide
      </a>
    </div>
  );
}
